from pathlib import Path
import openpyxl

def verify(workspace_path, external_services_path=None):
    xlsx_files = list(Path(workspace_path).glob('*Floorplan*Worksheet*April*.xlsx')) + list(Path(workspace_path).glob('*floorplan*worksheet*april*.xlsx'))
    if not xlsx_files:
        xlsx_files = list(Path(workspace_path).glob('*Floorplan*Worksheet*.xlsx')) + list(Path(workspace_path).glob('*floorplan*.xlsx'))
    if not xlsx_files:
        return {'pass': False, 'score': 0.0, 'feedback': 'No Floorplan_Worksheet_April2026.xlsx file found'}

    required_stocks = {'n2041', 'n2043', 'n2046', 'n2047', 'n2048', 'n2049', 'u1087', 'u1090', 'u1092', 'u1093'}
    expected_total = 319750

    for xlsx_file in xlsx_files:
        try:
            wb = openpyxl.load_workbook(xlsx_file, data_only=True)
            for sheet_name in wb.sheetnames:
                ws = wb[sheet_name]
                rows = list(ws.iter_rows(values_only=True))
                if not rows:
                    continue

                # Detect the Principal Balance column from the header row
                header = [str(c).strip().lower() if c is not None else '' for c in rows[0]]
                principal_col = None
                for idx, col_name in enumerate(header):
                    if 'principal' in col_name and 'balance' in col_name:
                        principal_col = idx
                        break
                if principal_col is None:
                    for idx, col_name in enumerate(header):
                        if 'principal' in col_name or col_name in ('balance', 'fp balance', 'floorplan balance'):
                            principal_col = idx
                            break

                found_stocks = set()
                principal_total = 0.0

                for row in rows[1:]:
                    row_str = [str(c).strip() if c is not None else '' for c in row]
                    row_joined = ' '.join(row_str).lower()

                    for stock in required_stocks:
                        if stock in row_joined:
                            found_stocks.add(stock)
                            # Extract principal from the identified column first
                            extracted = False
                            if principal_col is not None and principal_col < len(row):
                                cell = row[principal_col]
                                try:
                                    v = float(str(cell).replace('$', '').replace(',', '').strip())
                                    if v > 0:
                                        principal_total += v
                                        extracted = True
                                except (ValueError, TypeError):
                                    pass
                            # Fallback: scan for a value in 10k-100k range
                            if not extracted:
                                for c in row:
                                    try:
                                        v = float(str(c).replace('$', '').replace(',', '').strip())
                                        if 10000 <= v <= 100000:
                                            principal_total += v
                                            break
                                    except (ValueError, TypeError):
                                        pass

                missing = required_stocks - found_stocks
                total_diff = abs(principal_total - expected_total)

                if len(missing) == 0 and total_diff <= 100:
                    return {
                        'pass': True,
                        'score': 1.0,
                        'feedback': f'Found {len(found_stocks)}/10 required stocks in {xlsx_file.name}. Total: ${principal_total:,.0f} vs expected ${expected_total:,}.'
                    }
        except Exception as e:
            continue

    return {'pass': False, 'score': 0.0, 'feedback': f'Floorplan worksheet does not contain all 10 required units or total does not match $319,750. Files: {[f.name for f in xlsx_files]}'}

