        data = json.load(f)

    # Check channel C010
    channel_messages = data.get('messages', {}).get('C010', [])

    if not channel_messages:
        channels = data.get('channels', {})
        for ch_id, ch_info in channels.items():
            if 'acct-floorplan' in ch_info.get('name', '').lower() or 'floorplan' in ch_info.get('name', '').lower():
                channel_messages = data.get('messages', {}).get(ch_id, [])
                break

    if not channel_messages:
        return {'pass': False, 'score': 0.0, 'feedback': 'No messages found in channel C010 (#acct-floorplan)'}

    for msg in channel_messages:
        text = str(msg.get('text', '')).lower()

        checks = {}
        checks['n2048'] = 'n2048' in text
        checks['curtailment'] = 'aged curtailment' in text
        checks['days_on_floor'] = '94' in text
        checks['date'] = any(d in text for d in ['02/11/2026', '2/11/2026', '02/11', 'february 11'])
        checks['marcus'] = any(m in text for m in ['marcus', '@marcus', 'hale'])
        checks['elena'] = any(e in text for e in ['elena', '@elena', 'brooks'])

        failed = [k for k, v in checks.items() if not v]
        if len(failed) == 0:
            return {'pass': True, 'score': 1.0, 'feedback': f'Found N2048 aged curtailment Slack message in C010 with all required details.'}

    return {'pass': False, 'score': 0.0, 'feedback': f'No Slack message in C010 with N2048 aged curtailment details (94 days, 02/11/2026, Marcus/Elena tags). {len(channel_messages)} messages checked.'}

