from pathlib import Path
import openpyxl

def verify(workspace_path, external_services_path=None):
    # Search broadly for inventory used files
    ws_path = Path(workspace_path)
    xlsx_files = []
    for f in ws_path.rglob('*.xlsx'):
        fname_lower = f.name.lower()
        if 'inventory' in fname_lower and 'used' in fname_lower:
            xlsx_files.append(f)

    if not xlsx_files:
        # Even broader search
        xlsx_files = list(ws_path.rglob('*.xlsx'))

    if not xlsx_files:
        return {'pass': False, 'score': 0.0, 'feedback': 'No .xlsx files found in workspace'}

    found_u1093 = False
    details = []

    for xlsx_file in xlsx_files:
        try:
            wb = openpyxl.load_workbook(xlsx_file, data_only=True)
            for sheet_name in wb.sheetnames:
                ws = wb[sheet_name]
                rows = list(ws.iter_rows(values_only=True))
                if not rows:
                    continue

                # Try to find header row to identify columns
                header_row = None
                header_idx = -1
                for idx, row in enumerate(rows):
                    row_str = ' '.join([str(c).strip().lower() if c is not None else '' for c in row])
                    if 'stock' in row_str or 'recon' in row_str or 'book' in row_str or 'acv' in row_str:
                        header_row = row
                        header_idx = idx
                        break

                # Find column indices if we have headers
                recon_col = None
                book_cost_col = None
                acv_col = None
                pack_col = None
                if header_row:
                    for ci, cell in enumerate(header_row):
                        if cell is not None:
                            cell_lower = str(cell).strip().lower()
                            if 'recon' in cell_lower:
                                recon_col = ci
                            elif 'book' in cell_lower and ('cost' in cell_lower or 'value' in cell_lower):
                                book_cost_col = ci
                            elif 'book cost' in cell_lower:
                                book_cost_col = ci
                            elif cell_lower == 'acv' or 'acv' in cell_lower:
                                acv_col = ci
                            elif 'pack' in cell_lower:
                                pack_col = ci

                for row in rows:
                    row_str = [str(c).strip() if c is not None else '' for c in row]
                    row_joined = ' '.join(row_str).lower()

                    # Check if this row is about U1093 or 2022 BMW 330i
                    is_u1093 = 'u1093' in row_joined
                    is_bmw_330i = 'bmw' in row_joined and '330i' in row_joined

                    if not is_u1093 and not is_bmw_330i:
                        continue

                    found_u1093 = True

                    # Gather all numeric values from row
                    numeric_vals = []
                    for c in row:
                        if c is not None:
                            try:
                                v = float(str(c).replace('$', '').replace(',', '').strip())
                                numeric_vals.append(v)
                            except:
                                pass

                    # Check specific columns if available, otherwise check all numeric values
                    recon_ok = False
                    book_cost_ok = False
                    acv_ok = False

                    actual_recon = None
                    actual_book = None
                    actual_acv = None

                    # Try column-based checking first
                    if recon_col is not None and recon_col < len(row):
                        try:
                            val = float(str(row[recon_col]).replace('$', '').replace(',', '').strip())
                            actual_recon = val
                            if abs(val - 2800) <= 100:  # ~3.5% tolerance
                                recon_ok = True
                        except:
                            pass

                    if book_cost_col is not None and book_cost_col < len(row):
                        try:
                            val = float(str(row[book_cost_col]).replace('$', '').replace(',', '').strip())
                            actual_book = val
                            if abs(val - 33050) <= 500:  # ~1.5% tolerance
                                book_cost_ok = True
                        except:
                            pass

                    if acv_col is not None and acv_col < len(row):
                        try:
                            val = float(str(row[acv_col]).replace('$', '').replace(',', '').strip())
                            actual_acv = val
                            if abs(val - 29500) <= 500:  # ~1.7% tolerance
                                acv_ok = True
                        except:
                            pass

                    # Fall back to scanning all numeric values
                    if not recon_ok:
                        for v in numeric_vals:
                            if abs(v - 2800) <= 100:
                                recon_ok = True
                                if actual_recon is None:
                                    actual_recon = v
                                break

                    if not book_cost_ok:
                        for v in numeric_vals:
                            if abs(v - 33050) <= 500:
                                book_cost_ok = True
                                if actual_book is None:
                                    actual_book = v
                                break

                    if not acv_ok:
                        for v in numeric_vals:
                            if abs(v - 29500) <= 500:
                                acv_ok = True
                                if actual_acv is None:
                                    actual_acv = v
                                break

                    # Also check for double-posting: recon should NOT be ~5600 (doubled)
                    double_recon = any(abs(v - 5600) <= 200 for v in numeric_vals)
                    double_book = any(abs(v - 35850) <= 500 for v in numeric_vals)

                    if double_recon or double_book:
                        return {
                            'pass': False,
                            'score': 0.0,
                            'feedback': f'U1093 appears to have been double-posted (Invoice SBP-4812 applied twice). '
                                       f'Found suspicious values suggesting doubled recon (~5600) or inflated book cost (~35850). '
                                       f'Numeric values in row: {numeric_vals}. File: {xlsx_file.name}, Sheet: {sheet_name}'
                        }

                    checks = {
                        'Recon ~$2,800': recon_ok,
                        'Book Cost ~$33,050': book_cost_ok,
                        'ACV ~$29,500': acv_ok
                    }

                    failed = [k for k, v in checks.items() if not v]

                    if len(failed) <= 1 and recon_ok and book_cost_ok:
                        # Primary requirement is recon and book cost; ACV is supporting info
                        return {
                            'pass': True,
                            'score': 1.0,
                            'feedback': f'U1093 (2022 BMW 330i) found in {xlsx_file.name}, sheet "{sheet_name}" '
                                       f'with correct values: Recon={actual_recon}, Book Cost={actual_book}, ACV={actual_acv}. '
                                       f'No double-posting of Invoice SBP-4812 detected.'
                        }
                    else:
                        details.append(
                            f'U1093 found in {xlsx_file.name}, sheet "{sheet_name}" but checks failed: {failed}. '
                            f'Actual recon={actual_recon}, book_cost={actual_book}, acv={actual_acv}. '
                            f'Numeric values: {numeric_vals}'
                        )
        except Exception as e:
            details.append(f'Error reading {xlsx_file.name}: {str(e)}')
            continue

    if not found_u1093:
        return {
            'pass': False,
            'score': 0.0,
            'feedback': f'Could not find stock U1093 (2022 BMW 330i) in any Inventory Used file. '
                       f'Files checked: {[f.name for f in xlsx_files]}'
        }

    return {
        'pass': False,
        'score': 0.0,
        'feedback': f'Found U1093 but values do not match expected Recon=$2,800 and Book Cost=$33,050. '
                   f'Details: {" | ".join(details)}'
    }

