from pathlib import Path
import openpyxl

def verify(workspace_path, external_services_path=None):
    xlsx_files = list(Path(workspace_path).glob('*Floorplan*Worksheet*April*.xlsx')) + list(Path(workspace_path).glob('*floorplan*worksheet*april*.xlsx'))
    if not xlsx_files:
        xlsx_files = list(Path(workspace_path).glob('*Floorplan*Worksheet*.xlsx')) + list(Path(workspace_path).glob('*floorplan*.xlsx'))
    if not xlsx_files:
        return {'pass': False, 'score': 0.0, 'feedback': 'No Floorplan_Worksheet_April2026.xlsx file found'}

    all_feedback = []
    for xlsx_file in xlsx_files:
        try:
            wb = openpyxl.load_workbook(xlsx_file, data_only=True)
            exception_sheets = [s for s in wb.sheetnames if 'exception' in s.lower() or 'discrepancy' in s.lower() or 'resolution' in s.lower()]
            if not exception_sheets:
                all_feedback.append(f'{xlsx_file.name}: no Exception Log sheet found (sheets: {wb.sheetnames})')
                continue

            for sheet_name in exception_sheets:
                ws = wb[sheet_name]
                rows = list(ws.iter_rows(values_only=True))
                if not rows:
                    continue

                for row_idx, row in enumerate(rows[1:], start=2):
                    row_str = [str(c).strip() if c is not None else '' for c in row]
                    row_joined = ' '.join(row_str).lower()

                    if 'n2041' not in row_joined and '4t1g11ak6ru304501' not in row_joined:
                        continue

                    checks = {}
                    checks['deal_number'] = '4501' in row_joined
                    checks['customer'] = 'robert chen' in row_joined or 'chen' in row_joined
                    checks['stock_or_vin'] = 'n2041' in row_joined or '4t1g11ak6ru304501' in row_joined
                    normalized = row_joined.replace(',', '').replace('$', '').replace(' ', '')
                    checks['variance_amount'] = '28250' in normalized or '185' in row_joined
                    checks['source_document'] = 'jm family' in row_joined or 'lender statement' in row_joined
                    checks['classification'] = 'accounting error' in row_joined

                    failed = [k for k, v in checks.items() if not v]
                    if len(failed) == 0:
                        return {'pass': True, 'score': 1.0, 'feedback': f'Found N2041 discrepancy resolution entry in {xlsx_file.name}, sheet "{sheet_name}", row {row_idx} with all five required facts and Accounting Error classification.'}
                    else:
                        all_feedback.append(f'N2041 entry found in {xlsx_file.name} sheet "{sheet_name}" row {row_idx} but failed: {failed}. Row: {row_str}')
        except Exception as e:
            all_feedback.append(f'Error reading {xlsx_file.name}: {str(e)}')
            continue

    if all_feedback:
        return {'pass': False, 'score': 0.0, 'feedback': 'N2041 entry found but incomplete. ' + ' | '.join(all_feedback)}
    return {'pass': False, 'score': 0.0, 'feedback': f'No N2041 discrepancy resolution entry found in any Exception Log sheet. Files checked: {[f.name for f in xlsx_files]}'}
